// Parse incoming foreman update
const raw = $input.item.json.body || $input.item.json;

const jobSite = raw.job_site || raw.jobSite || '';
const percentComplete = parseInt(raw.percent_complete || raw.percentComplete || raw.progress || '0');
const blockers = raw.blockers || raw.blocker || '';
const photoUrl = raw.photo_url || raw.photoUrl || raw.photo || '';
const foremanName = raw.foreman_name || raw.foremanName || raw.foreman || '';
const foremanNote = raw.foreman_note || raw.foremanNote || raw.note || raw.notes || raw.update || '';
const jobId = raw.job_id || raw.jobId || 'JOB-UNKNOWN';
const updateDate = raw.update_date || raw.updateDate || new Date().toISOString().split('T')[0];

return [{ json: {
  job_id: jobId,
  job_site: jobSite,
  percent_complete: percentComplete,
  blockers: blockers,
  photo_url: photoUrl,
  foreman_name: foremanName,
  foreman_note: foremanNote,
  update_date: updateDate,
  received_at: new Date().toISOString()
}}];

// CANONICAL NODE — all downstream nodes reference this
const ai = (() => {
  try {
    const r = $('AI Classify Job Type + Compliance').item.json;
    const c = (r.content && r.content[0]) ? r.content[0].text : '';
    const m = c.match(/\{[\s\S]*\}/);
    return JSON.parse(m ? m[0] : c);
  } catch(e) { return null; }
})();

const input = $('Parse Foreman Update').item.json;

const jobType = ai ? ai.job_type : 'unknown';
const status = ai ? ai.status : (input.blockers ? 'blocked' : 'on_track');
const complianceFlags = ai && ai.compliance_flags ? ai.compliance_flags : [];
const permitAlert = ai ? ai.permit_alert : 'no';
const stalledDetection = ai ? ai.stalled_detection : 'no';
const foremanSummary = ai ? ai.foreman_summary : input.foreman_note;
const clientSummary = ai ? ai.client_summary : 'Work is progressing on ' + input.job_site + '.';
const nextMilestone = ai ? ai.next_milestone : 'TBD';
const riskFactors = ai && ai.risk_factors ? ai.risk_factors : (input.blockers ? [input.blockers] : []);

// Status color for dashboard
const statusColor = status === 'blocked' ? '🔴' : status === 'at_risk' ? '🟠' : '🟢';

// Compliance report body
const complianceReport = complianceFlags.length > 0
  ? '<p><b>Compliance items addressed this period:</b></p><ul>' + complianceFlags.map(f => '<li>' + f + '</li>').join('') + '</ul>'
  : '<p>No compliance items triggered this period.</p>';

// Client report — type-specific formatting
const jobTypeLabel = jobType.replace('_', ' ').toUpperCase();
const clientReportSubject = input.job_site + ' — ' + jobTypeLabel + ' Progress Update (' + input.percent_complete + '%)';
const clientReportBody = '<h2>' + jobTypeLabel + ' Progress Update</h2>' +
  '<p><b>Project:</b> ' + input.job_site + '</p>' +
  '<p><b>Overall Progress:</b> ' + input.percent_complete + '% complete</p>' +
  '<p><b>Status:</b> ' + statusColor + ' ' + status.replace('_', ' ').toUpperCase() + '</p>' +
  '<hr>' +
  '<p>' + clientSummary + '</p>' +
  '<p><b>Next Milestone:</b> ' + nextMilestone + '</p>' +
  '<hr>' +
  complianceReport +
  '<hr><p style="color:#888;font-size:12px;">This update was generated automatically from your contractor\'s field report.</p>';

// Owner alert (Vincent) — triggered for blocked, stalled, or permit alerts
const ownerAlertNeeded = status === 'blocked' || stalledDetection === 'yes' || permitAlert === 'yes';
const ownerAlertSubject = ownerAlertNeeded
  ? (status === 'blocked' ? '🔴 BLOCKED: ' : stalledDetection === 'yes' ? '🟠 STALLED: ' : '🔔 PERMIT ALERT: ') + input.job_site
  : 'Job Status Update: ' + input.job_site;
const ownerAlertBody = '<h2 style="color:' + (status === 'blocked' ? 'red' : '#e67e00') + ';">' + jobTypeLabel + ' — ' + input.job_site + '</h2>' +
  '<p><b>Foreman:</b> ' + input.foreman_name + '</p>' +
  '<p><b>Progress:</b> ' + input.percent_complete + '%</p>' +
  '<p><b>Status:</b> ' + statusColor + ' ' + status.replace('_', ' ').toUpperCase() + '</p>' +
  (input.blockers ? '<p><b>Blocker:</b> ' + input.blockers + '</p>' : '') +
  (stalledDetection === 'yes' ? '<p style="color:#e67e00;"><b>⚠ Stalled: No significant progress since last update.</b></p>' : '') +
  (permitAlert === 'yes' ? '<p style="color:#e67e00;"><b>🔔 Permit action required — review permit tracker.</b></p>' : '') +
  '<p><b>Foreman Summary:</b> ' + foremanSummary + '</p>' +
  (riskFactors.length > 0 ? '<p><b>Risk Factors:</b></p><ul>' + riskFactors.map(r => '<li>' + r + '</li>').join('') + '</ul>' : '') +
  '<p><b>Next Milestone:</b> ' + nextMilestone + '</p>';

return [{ json: {
  // Raw inputs
  job_id: input.job_id,
  job_site: input.job_site,
  percent_complete: input.percent_complete,
  blockers: input.blockers,
  photo_url: input.photo_url,
  foreman_name: input.foreman_name,
  foreman_note: input.foreman_note,
  update_date: input.update_date,
  received_at: input.received_at,
  // AI classified
  job_type: jobType,
  status: status,
  status_emoji: statusColor,
  compliance_flags: complianceFlags,
  permit_alert: permitAlert,
  stalled_detection: stalledDetection,
  foreman_summary: foremanSummary,
  client_summary: clientSummary,
  next_milestone: nextMilestone,
  risk_factors: riskFactors,
  report_cadence_override: ai && ai.report_cadence_override ? ai.report_cadence_override : 'inherit',
  // Email content
  client_email_subject: clientReportSubject,
  client_email_body: clientReportBody,
  owner_alert_subject: ownerAlertSubject,
  owner_alert_body: ownerAlertBody,
  owner_alert_needed: ownerAlertNeeded,
  // Timestamps
  processed_at: new Date().toISOString()
}}];

// Process new job creation — AI classified fields
const ai = (() => {
  try {
    const r = $('AI Classify New Job').item.json;
    const c = (r.content && r.content[0]) ? r.content[0].text : '';
    const m = c.match(/\{[\s\S]*\}/);
    return JSON.parse(m ? m[0] : c);
  } catch(e) { return null; }
})();

const input = $('Parse New Job Data').item.json;

const jobType = ai ? ai.job_type : input.job_type;
const complianceTags = ai && ai.compliance_tags ? ai.compliance_tags : (input.compliance_tags || []);
const permits = ai && ai.permit_required ? ai.permit_required : (input.permit_required || []);
const cadence = ai && ai.reporting_cadence ? ai.reporting_cadence : (input.reporting_cadence || 'weekly');
const vincentAlert = ai ? ai.vincent_alert : 'no';

return [{ json: {
  job_id: input.job_id,
  job_site: input.job_site,
  job_type: jobType,
  client: input.client,
  foreman: input.foreman,
  contract_value: input.contract_value,
  start_date: input.start_date,
  target_end_date: input.target_end_date,
  permit_status: input.permit_status,
  permits_required: permits,
  compliance_tags: complianceTags,
  reporting_cadence: cadence,
  client_email: input.client_email,
  vincent_alert: vincentAlert,
  status: 'on_track',
  percent_complete: 0,
  created_at: input.created_at
}}];

// Build compliance log row — only if flags exist
const d = $('Build Canonical Job Record').item.json;
const flags = d.compliance_flags || [];
if (flags.length === 0) { return []; }
return flags.map(flag => ({ json: {
  'Date': new Date().toISOString().split('T')[0],
  'Job ID': d.job_id,
  'Job Site': d.job_site,
  'Job Type': d.job_type,
  'Compliance Flag': flag,
  'Status': d.status,
  'Reported': 'Yes'
}}));

// Extract client notification data from canonical record
const d = $('Build Canonical Job Record').item.json;
// Client email would come from a lookup in the pipeline sheet
// For now: email derived from job type
const clientEmailMap = {
  hospital: 'facilities@placeholder-hospital.com',
  school: 'admin@placeholder-school.edu',
  tenant_improvement: 'property@placeholder-landlord.com',
  flood_restoration: 'claims@placeholder-insurance.com',
  maintenance: 'pm@placeholder-pm.com',
  commercial: 'owner@placeholder-owner.com'
};
return [{ json: {
  send_to: clientEmailMap[d.job_type] || 'owner@gnetconstruction.com',
  email_subject: d.client_email_subject,
  email_body: d.client_email_body
}}];

// Prep Vincent alert — blocked, stalled, or permit alert
const d = $('Build Canonical Job Record').item.json;
return [{ json: {
  send_to: 'vincent@gnetconstruction.com',
  email_subject: d.owner_alert_subject,
  email_body: d.owner_alert_body
}}];

const d = $('Build New Job Record').item.json;
return [{ json: {
  success: true,
  job_id: d.job_id,
  job_site: d.job_site,
  job_type: d.job_type,
  compliance_tags: d.compliance_tags,
  permits_required: d.permits_required,
  reporting_cadence: d.reporting_cadence,
  actions: ['Added to Pipeline sheet', d.vincent_alert === 'yes' ? 'Vincent alerted for hospital/school/flood job' : 'No Vincent alert needed'],
  created_at: d.created_at
}}];

const e = $input.item.json;
return [{ json: {
  error: true,
  error_message: e.message || 'Unknown error',
  workflow: 'G-Net Construction Dashboard',
  timestamp: new Date().toISOString()
}}];
